exercises.expected_solution:
import java.util.*;
import java.util.stream.*;
class Product { 
    String name;
    Product(String n) { name=n; }
    public String toString() { return name; }
}
public class App {
    static List<Product> getPage(List<Product> all, int page, int pageSize) {
        return all.stream()
            .sorted(Comparator.comparing(p -> p.name))
            .skip((long)(page - 1) * pageSize)
            .limit(pageSize)
            .collect(Collectors.toList());
    }

    public static void main(String[] args) {
        List<Product> products = Arrays.asList(
            new Product("USB Hub"), new Product("Keyboard"), new Product("Mouse"),
            new Product("Monitor"), new Product("Headphones"), new Product("Webcam"),
            new Product("SSD"), new Product("RAM"), new Product("CPU"), new Product("GPU")
        );

        List<Product> page2 = getPage(products, 2, 3);
        System.out.println("Page 2 (sorted by name, size 3):");
        page2.forEach(p -> System.out.println(p.name));
    }
}

