import java.util.*;
import java.util.stream.*;
class Sale {
    String product; int qty;
    Sale(String p, int q) { product=p; qty=q; }
}
public class App {
    public static void main(String[] args) {
        List<Sale> sales = Arrays.asList(
            new Sale("Mouse",       350),
            new Sale("Keyboard",     85),
            new Sale("USB Hub",     420),
            new Sale("Monitor",     120),
            new Sale("Headphones",   95),
            new Sale("Laptop Stand",280)
        );

        List<Sale> top3 = sales.stream()
            .filter(s -> s.qty > 100)
            .sorted((a, b) -> Integer.compare(b.qty, a.qty))
            .limit(3)
            .collect(Collectors.toList());

        for (int i = 0; i < top3.size(); i++) {
            Sale s = top3.get(i);
            System.out.println("#" + (i+1) + " " + s.product + ": " + s.qty + " units");
        }
    }
}

