import java.util.*;
import java.util.stream.*;
class Product {
    String name, category;
    double price, rating;
    boolean inStock;
    Product(String n, String c, double p, double r, boolean s) {
        name=n; category=c; price=p; rating=r; inStock=s;
    }
}
public class App {
    public static void main(String[] args) {
        List<Product> catalog = Arrays.asList(
            new Product("Mouse",      "Electronics", 799,  4.2, true),
            new Product("Keyboard",   "Electronics", 1999, 4.7, true),
            new Product("Headphones", "Electronics", 2999, 4.5, false),
            new Product("Java Book",  "Books",        649,  4.3, true),
            new Product("Python Book","Books",        549,  4.0, true),
            new Product("Monitor",    "Electronics", 3798, 4.8, true)
        );

        // 1. Inventory value
        double total = catalog.stream()
            .filter(p -> p.inStock)
            .mapToDouble(p -> p.price)
            .sum();
        System.out.println("Inventory value: ₹" + total);

        // 2. Top 2 rated
        List<String> top2 = catalog.stream()
            .sorted((a,b) -> Double.compare(b.rating, a.rating))
            .limit(2)
            .map(p -> p.name)
            .collect(Collectors.toList());
        System.out.println("Top 2 rated: " + top2);

        // 3. All books under 1000
        boolean booksUnder1k = catalog.stream()
            .filter(p -> p.category.equals("Books"))
            .allMatch(p -> p.price < 1000);
        System.out.println("All books under ₹1000: " + booksUnder1k);

        // 4. Distinct categories
        long cats = catalog.stream()
            .map(p -> p.category)
            .distinct()
            .count();
        System.out.println("Distinct categories: " + cats);

        // 5. Most expensive OOS
        String oosName = catalog.stream()
            .filter(p -> !p.inStock)
            .max(Comparator.comparingDouble(p -> p.price))
            .map(p -> p.name)
            .orElse("None");
        System.out.println("Most expensive OOS: " + oosName);
    }
}

