import java.util.*;
import java.util.stream.*;
class Holding {
    String symbol;
    int shares;
    double buyPrice, currentPrice;
    Holding(String sym, int sh, double buy, double cur) {
        symbol=sym; shares=sh; buyPrice=buy; currentPrice=cur;
    }
    double value()   { return shares * currentPrice; }
    double gainPct() { return (currentPrice / buyPrice - 1) * 100; }
    boolean isProfitable() { return currentPrice > buyPrice; }
}
public class App {
    public static void main(String[] args) {
        List<Holding> portfolio = Arrays.asList(
            new Holding("TCS",      10, 2760, 3890),  // gain 41%
            new Holding("RELIANCE", 20, 2197, 2450),  // gain 11.5%
            new Holding("WIPRO",   100,  450,  412),  // loss
            new Holding("HDFC",     15, 1369, 1678)   // gain 22.6%
        );

        // 1. Total value
        double total = portfolio.stream()
            .mapToDouble(Holding::value)
            .sum();
        System.out.println("Total value: ₹" + total);

        // 2. Profitable symbols sorted
        List<String> profitable = portfolio.stream()
            .filter(Holding::isProfitable)
            .map(h -> h.symbol)
            .sorted()
            .collect(Collectors.toList());
        System.out.println("Profitable: " + profitable);

        // 4. allMatch (checking before top3 to get cleaner output order)
        boolean allProfit = portfolio.stream().allMatch(Holding::isProfitable);
        if (!allProfit) {
            String loser = portfolio.stream()
                .filter(h -> !h.isProfitable())
                .map(h -> h.symbol)
                .findFirst().orElse("??");
            System.out.println("Not all profitable: " + loser + " at loss");
        }

        // 3. Top 3 by gain%
        List<String> top3 = portfolio.stream()
            .sorted((a,b) -> Double.compare(b.gainPct(), a.gainPct()))
            .limit(3)
            .map(h -> String.format("%s(%+.1f%%)", h.symbol, h.gainPct()))
            .collect(Collectors.toList());
        System.out.println("Top 3 by gain%: " + top3);

        // 5. All symbols joined
        String all = portfolio.stream()
            .map(h -> h.symbol)
            .sorted()
            .collect(Collectors.joining(", "));
        System.out.println("Portfolio: " + all);
    }
}
